  /// Initialize the on-device database.
  /// In production this forwards to the Rust `db_init` via FRB.
  /// For Phase 1 this shim creates a local file at the provided path.
  static Future<void> dbInit(String dbUrl) async {
    // Accepts file path or "file:/absolute/path"
    var path = dbUrl;
    if (path.startsWith('file:')) {
      path = path.substring(5);
    }
    final file = File(path);
    await file.create(recursive: true);
    // Optionally write an SQLite header to identify the file as a DB
